734 |         async function decryptCtx(buffer) {
735 |             const keyBytes = new TextEncoder().encode("C0rtexS3cr3tK3y!");
736 |             const iv = buffer.slice(0, 12);
737 |             const ciphertext = buffer.slice(12);
738 |             
739 |             const cryptoKey = await crypto.subtle.importKey("raw", keyBytes, { name: "AES-GCM" }, false, ["decrypt"]);
740 |             const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv: iv }, cryptoKey, ciphertext);
741 |             
742 |             const decompressedBuffer = await decompressGzip(decrypted);
743 |             return JSON.parse(new TextDecoder().decode(decompressedBuffer));
744 |         }
