746 |         async function decompressGzip(buffer) {
747 |             const ds = new DecompressionStream("gzip");
748 |             const writer = ds.writable.getWriter();
749 |             writer.write(buffer);
750 |             writer.close();
751 |             const response = new Response(ds.readable);
752 |             return await response.arrayBuffer();
753 |         }
